DROP TABLE IF EXISTS `forum_report`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `forum_report` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `addtime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `forum_id` bigint(20) DEFAULT NULL COMMENT '论坛Id',
  `title` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '帖子标题',
  `report_userid` bigint(20) NOT NULL COMMENT '举报人id',
  `report_username` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '举报人账号',
  `reported_userid` bigint(20) NOT NULL COMMENT '被举报人id',
  `reported_username` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '被举报人账号',
  `reason` longtext COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '举报原因',
  `images` longtext COLLATE utf8mb4_unicode_ci COMMENT '举报图片',
  `suggestion` longtext COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '处理建议',
  `status` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT '待处理' COMMENT '处理状态',
  `report_type` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT '主题帖举报' COMMENT '举报类型',
  `userid` bigint(20) NOT NULL COMMENT '用户id',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='论坛举报';
